        { type: 'pause', durationSec: 60 },
        { type: 'invitation', text: 'Six minutes. The rhythm is doing the work.' },
        { type: 'pause', durationSec: 60 },
        { type: 'invitation', text: 'Seven minutes. Notice the steadiness underneath you.' },
        { type: 'pause', durationSec: 60 },
        { type: 'invitation', text: 'Eight minutes. Two more.' },
        { type: 'pause', durationSec: 60 },
        { type: 'invitation', text: 'Nine minutes. One more minute. Stay with it.' },
        { type: 'pause', durationSec: 60 },
        { type: 'invitation', text: 'Final minute. Let this be the most spacious one yet.' },
        { type: 'pause', durationSec: 50 },
        { type: 'close', text: 'Let your breath return to its natural rhythm. Notice your heart. Notice your mind. This is the coherent state. You can return here anytime.' }
